local P=game:GetService("Players");local UIS=game:GetService("UserInputService");local RS=game:GetService("RunService");local TS=game:GetService("TweenService");local L=game:GetService("Lighting")
local pl=P.LocalPlayer;local pg=pl:WaitForChild("PlayerGui");local m=pl:GetMouse();local cam=workspace.CurrentCamera
UIS.MouseBehavior=Enum.MouseBehavior.Default;UIS.MouseIconEnabled=true

local notifGui=Instance.new("ScreenGui",pg);notifGui.Name="KittyNotif";notifGui.ResetOnSpawn=false;notifGui.DisplayOrder=9999

-- ════════════════════════════════
--   НОВАЯ СИСТЕМА УВЕДОМЛЕНИЙ (стек из 2 сообщений, уезжают вправо)
-- ════════════════════════════════
local notifQueue = {}
local notifSpacing = 60
local notifStartY = -70

local function showNotif(text, color)
    color = color or Color3.fromRGB(90,80,200)
    
    local frame = Instance.new("Frame", notifGui)
    frame.Size = UDim2.new(0,260,0,50)
    frame.Position = UDim2.new(1,20,1,notifStartY)
    frame.BackgroundColor3 = Color3.fromRGB(10,8,20)
    frame.BorderSizePixel = 0
    frame.ZIndex = 10
    Instance.new("UICorner", frame).CornerRadius = UDim.new(0,10)
    
    local st = Instance.new("UIStroke", frame)
    st.Color = color
    st.Thickness = 1.2
    st.Transparency = 0.2
    
    local bar = Instance.new("Frame", frame)
    bar.Size = UDim2.new(0,3,1,-12)
    bar.Position = UDim2.new(0,0,0,6)
    bar.BackgroundColor3 = color
    bar.BorderSizePixel = 0
    Instance.new("UICorner", bar).CornerRadius = UDim.new(0,4)
    
    local lbl = Instance.new("TextLabel", frame)
    lbl.Size = UDim2.new(1,-18,1,0)
    lbl.Position = UDim2.new(0,14,0,0)
    lbl.BackgroundTransparency = 1
    lbl.Text = text
    lbl.TextColor3 = Color3.fromRGB(215,212,255)
    lbl.TextSize = 13
    lbl.Font = Enum.Font.GothamSemibold
    lbl.TextWrapped = true
    lbl.TextXAlignment = Enum.TextXAlignment.Left
    lbl.ZIndex = 11
    
    -- Анимация появления
    TS:Create(frame, TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.Out), {
        Position = UDim2.new(1,-275,1,notifStartY)
    }):Play()
    
    local notifData = { frame = frame, yOffset = notifStartY }
    table.insert(notifQueue, 1, notifData)
    
    -- Обновляем позиции всех уведомлений
    local function updatePositions()
        for i, data in ipairs(notifQueue) do
            local newY = notifStartY - (i - 1) * notifSpacing
            if data.frame and data.frame.Parent then
                data.frame.Position = UDim2.new(1,-275,1,newY)
                data.yOffset = newY
            end
        end
    end
    updatePositions()
    
    -- Если больше 2 уведомлений, удаляем самое старое (уезжает вправо)
    if #notifQueue > 2 then
        local oldest = table.remove(notifQueue)
        if oldest and oldest.frame and oldest.frame.Parent then
            local tweenOut = TS:Create(oldest.frame, TweenInfo.new(0.4, Enum.EasingStyle.Quint, Enum.EasingDirection.In), {
                Position = UDim2.new(1,20,1,oldest.yOffset)
            })
            tweenOut:Play()
            tweenOut.Completed:Connect(function()
                if oldest.frame then oldest.frame:Destroy() end
            end)
        end
    end
    
    -- Автоудаление через 4 секунды (уезжает вправо)
    task.delay(4, function()
        for i, data in ipairs(notifQueue) do
            if data.frame == frame then
                table.remove(notifQueue, i)
                if frame and frame.Parent then
                    local tweenOut = TS:Create(frame, TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.In), {
                        Position = UDim2.new(1,20,1,data.yOffset)
                    })
                    tweenOut:Play()
                    tweenOut.Completed:Connect(function()
                        if frame then frame:Destroy() end
                    end)
                end
                updatePositions()
                break
            end
        end
    end)
end

local function getRoot()local c=pl.Character return c and c:FindFirstChild("HumanoidRootPart")end
local function neonPart(sz,col,trans)local p=Instance.new("Part")p.Size=Vector3.new(sz,sz,sz);p.Shape=Enum.PartType.Ball;p.Material=Enum.Material.Neon;p.Color=col;p.CastShadow=false;p.CanCollide=false;p.Anchored=true;p.Transparency=trans or 0.1;return p end

local globalColor=Color3.fromRGB(80,160,255);local globalColor2=Color3.fromRGB(160,80,255)
local glowEnabled=true;local glowedParts={};local glowConn=nil;local lastGlowTarget=nil

local function clearGlow()for p,o in pairs(glowedParts)do if p and p.Parent then p.Color=o.Color;p.Transparency=o.Transparency end end;glowedParts={};lastGlowTarget=nil;if glowConn then glowConn:Disconnect();glowConn=nil end end

local function applyGlowToModel(model)if not model then return end;local parts={};if model:IsA("BasePart")then table.insert(parts,model)end;for _,v in ipairs(model:GetDescendants())do if v:IsA("BasePart")then table.insert(parts,v)end end;for _,p in ipairs(parts)do if not glowedParts[p]then glowedParts[p]={Color=p.Color,Transparency=p.Transparency}end;p.Color=globalColor;p.Transparency=0.3 end;if glowConn then glowConn:Disconnect()end;glowConn=RS.Heartbeat:Connect(function()for p in pairs(glowedParts)do if p and p.Parent then p.Color=globalColor end end end)end

RS.Heartbeat:Connect(function()if not glowEnabled then if lastGlowTarget then clearGlow()end;return end;if not m then return end;local t=m.Target;local ch=pl.Character;if not t or not t:IsA("BasePart")then if lastGlowTarget then clearGlow()end;return end;if ch and t:IsDescendantOf(ch)then if lastGlowTarget then clearGlow()end;return end;local ign={"KittySnow","KittyTrail","KittyOrbit","KittyCage","KittySparks","KittyRainbow"}for _,f in ipairs(ign)do local fd=workspace:FindFirstChild(f)if fd and t:IsDescendantOf(fd)then return end end;if t.Anchored then if lastGlowTarget then clearGlow()end;return end;local mod=t;local anc=t.Parent;if anc and anc:IsA("Model")and anc~=workspace then mod=anc end;if mod==lastGlowTarget then return end;clearGlow();lastGlowTarget=mod;applyGlowToModel(mod)end)
m.Button1Up:Connect(function()task.delay(0.5,function()if lastGlowTarget then clearGlow()end end)end)

