-- Snow
local snowParts={};local snowActive=false;local snowConn=nil;local snowFolder=Instance.new("Folder",workspace);snowFolder.Name="KittySnow"
local function startSnow()if snowActive then return end;snowActive=true;local spread=160;local height=80;for i=1,600 do local root=getRoot()if not root then break end;local sz=0.35+math.random()*(0.85-0.35);local p=neonPart(sz,Color3.fromRGB(200,225,255),0.1);local rp=root.Position;p.Position=Vector3.new(rp.X+math.random(-spread,spread),rp.Y+math.random(0,height),rp.Z+math.random(-spread,spread));p.Parent=snowFolder;table.insert(snowParts,{part=p,speed=12+math.random()*18})end;snowConn=RS.Heartbeat:Connect(function(dt)if not snowActive then return end;local root=getRoot()if not root then return end;local rpos=root.Position;for _,f in ipairs(snowParts)do local p=f.part;if p and p.Parent then local fp=p.Position;local ny=fp.Y-f.speed*dt;if ny<rpos.Y-12 then p.Position=Vector3.new(rpos.X+math.random(-spread,spread),rpos.Y+height,rpos.Z+math.random(-spread,spread))else p.Position=Vector3.new(fp.X+math.sin(tick()*0.9+fp.X*0.5)*0.4*dt,ny,fp.Z+math.cos(tick()*0.7+fp.Z*0.5)*0.3*dt)end end end end);showNotif("Снег запущен! (600 снежинок)",Color3.fromRGB(100,160,220))end
local function stopSnow()snowActive=false;if snowConn then snowConn:Disconnect();snowConn=nil end;for _,f in ipairs(snowParts)do if f.part and f.part.Parent then f.part:Destroy()end end;snowParts={};showNotif("Снег остановлен!",Color3.fromRGB(90,90,150))end

