-- Orbit
local orbitActive=false;local orbitConn=nil;local orbitFolder=Instance.new("Folder",workspace);orbitFolder.Name="KittyOrbit";local orbitParts={}
local function startOrbit(cA,cB,lbl)if orbitConn then orbitConn:Disconnect();orbitConn=nil end;for _,p in ipairs(orbitParts)do if p and p.Parent then p:Destroy()end end;orbitParts={};orbitActive=true;cA=cA or globalColor;cB=cB or globalColor2;local COUNT=80;local RADIUS=8;for i=1,COUNT do local p=Instance.new("Part");p.Size=Vector3.new(0.55,0.55,0.55);p.Shape=Enum.PartType.Ball;p.Material=Enum.Material.Neon;p.Color=cA;p.CastShadow=false;p.CanCollide=false;p.Anchored=true;p.Transparency=0.05;p.Parent=orbitFolder;table.insert(orbitParts,p)end;local TAIL=20;for i=1,TAIL do local p=Instance.new("Part");local sz=0.9*(1-i/TAIL)+0.15;p.Size=Vector3.new(sz,sz,sz);p.Shape=Enum.PartType.Ball;p.Material=Enum.Material.Neon;p.Color=cB;p.CastShadow=false;p.CanCollide=false;p.Anchored=true;p.Transparency=0.0;p.Parent=orbitFolder;table.insert(orbitParts,p)end;local t0=tick();orbitConn=RS.Heartbeat:Connect(function()local root=getRoot()if not root then return end;local pos=root.Position;local t=(tick()-t0);local sp=1.4;for i,p in ipairs(orbitParts)do if i>COUNT then break end;if p and p.Parent then local ang=(i/COUNT)*math.pi*2+t*sp;local x=math.cos(ang)*RADIUS;local y=math.sin(ang)*RADIUS*0.35+math.sin(t*0.5)*0.8;local z=math.sin(ang)*RADIUS;p.Position=Vector3.new(pos.X+x,pos.Y+y,pos.Z+z);local mix=(math.sin(t*2+i*0.2)+1)/2;p.Color=Color3.new(cA.R+(cB.R-cA.R)*mix,cA.G+(cB.G-cA.G)*mix,cA.B+(cB.B-cA.B)*mix);local pls=0.45+math.sin(t*3+i*0.15)*0.1;p.Size=Vector3.new(pls,pls,pls)end end;local headAng=t*sp;for j=1,TAIL do local idx=COUNT+j;local p=orbitParts[idx];if p and p.Parent then local a=headAng-j*0.12;local x=math.cos(a)*RADIUS;local y=math.sin(a)*RADIUS*0.35+math.sin(t*0.5)*0.8;local z=math.sin(a)*RADIUS;p.Position=Vector3.new(pos.X+x,pos.Y+y,pos.Z+z);local fade=1-(j/TAIL);p.Transparency=1-fade*0.95;local sz=(0.9*fade)+0.1;p.Size=Vector3.new(sz,sz,sz);p.Color=cB end end end);showNotif(lbl or "Орбита включена!",cA)end
local function stopOrbit()orbitActive=false;if orbitConn then orbitConn:Disconnect();orbitConn=nil end;for _,p in ipairs(orbitParts)do if p and p.Parent then p:Destroy()end end;orbitParts={};showNotif("Орбита выключена!",Color3.fromRGB(80,80,140))end

