local function startTrail(cA,cB,lbl)if trailObj then trailObj:Destroy();trailObj=nil end;if att0 then att0:Destroy();att0=nil end;if att1 then att1:Destroy();att1=nil end;if trailConn then trailConn:Disconnect();trailConn=nil end;trailActive=true;cA=cA or globalColor;cB=cB or globalColor2;local function attach()local ch=pl.Character;if not ch then return end;local root=ch:FindFirstChild("HumanoidRootPart");if not root then return end;att0=Instance.new("Attachment",root);att0.Position=Vector3.new(0,1,0);att1=Instance.new("Attachment",root);att1.Position=Vector3.new(0,-1,0);trailObj=Instance.new("Trail",root);trailObj.Attachment0=att0;trailObj.Attachment1=att1;trailObj.Lifetime=0.8;trailObj.MinLength=0;trailObj.FaceCamera=true;trailObj.LightEmission=1;trailObj.LightInfluence=0;trailObj.Color=ColorSequence.new({ColorSequenceKeypoint.new(0,cA),ColorSequenceKeypoint.new(1,cB)});trailObj.Transparency=NumberSequence.new({NumberSequenceKeypoint.new(0,0),NumberSequenceKeypoint.new(1,1)});trailObj.WidthScale=NumberSequence.new({NumberSequenceKeypoint.new(0,1),NumberSequenceKeypoint.new(1,0)})end;attach();trailConn=pl.CharacterAdded:Connect(function()task.wait(0.5);if trailActive then attach()end end);showNotif(lbl or "След включён!",cA)end
local function stopTrail()trailActive=false;if trailObj then trailObj:Destroy();trailObj=nil end;if att0 then att0:Destroy();att0=nil end;if att1 then att1:Destroy();att1=nil end;if trailConn then trailConn:Disconnect();trailConn=nil end;showNotif("След выключен!",Color3.fromRGB(70,90,150))end

-- Rainbow
local rainbowActive=false;local rainbowConn=nil;local rainbowFolder=Instance.new("Folder",workspace);rainbowFolder.Name="KittyRainbow";local rainbowParts={}
local function startRainbow()if rainbowActive then return end;rainbowActive=true;rainbowConn=RS.Heartbeat:Connect(function(dt)local root=getRoot()if not root then return end;local pos=root.Position;local h=(tick()*0.4)%1;local p=Instance.new("Part");p.Size=Vector3.new(0.8,0.12,0.8);p.Material=Enum.Material.Neon;p.Color=Color3.fromHSV(h,1,1);p.CastShadow=false;p.CanCollide=false;p.Anchored=true;p.Transparency=0.05;p.Position=Vector3.new(pos.X+math.random(-10,10)*0.1,pos.Y-2.8,pos.Z+math.random(-10,10)*0.1);p.Parent=rainbowFolder;table.insert(rainbowParts,{part=p,born=tick()});local now=tick();for i=#rainbowParts,1,-1 do local rp=rainbowParts[i];if rp.part and rp.part.Parent then local age=now-rp.born;if age>0.8 then rp.part:Destroy();table.remove(rainbowParts,i)else rp.part.Transparency=0.05+(age/0.8)*0.95;local s=0.8+age*1.2;rp.part.Size=Vector3.new(s,0.12,s)end else table.remove(rainbowParts,i)end end end);showNotif("Радуга под ногами включена!",Color3.fromRGB(255,120,200))end
local function stopRainbow()rainbowActive=false;if rainbowConn then rainbowConn:Disconnect();rainbowConn=nil end;for _,rp in ipairs(rainbowParts)do if rp.part and rp.part.Parent then rp.part:Destroy()end end;rainbowParts={};showNotif("Радуга выключена!",Color3.fromRGB(140,80,150))end

-- Cage
local cageActive=false;local cageConn=nil;local cageFolder=Instance.new("Folder",workspace);cageFolder.Name="KittyCage";local cageParts={}
local function startCage(col,lbl)if cageConn then cageConn:Disconnect();cageConn=nil end;for _,p in ipairs(cageParts)do if p and p.Parent then p:Destroy()end end;cageParts={};cageActive=true;col=col or globalColor;local rings={{axis="X",offset=0},{axis="Y",offset=math.pi/3},{axis="Z",offset=math.pi*2/3}};local COUNT=30;local RADIUS=4.5;for _,ring in ipairs(rings)do for i=1,COUNT do local p=neonPart(0.3,col,0.05);p.Parent=cageFolder;table.insert(cageParts,{part=p,ring=ring,idx=i,total=COUNT})end end;local t0=tick();cageConn=RS.Heartbeat:Connect(function()local root=getRoot()if not root then return end;local pos=root.Position;local t=(tick()-t0)*1.1;for _,cp in ipairs(cageParts)do if cp.part and cp.part.Parent then local ang=(cp.idx/cp.total)*math.pi*2+t+cp.ring.offset;local x,y,z=0,0,0;if cp.ring.axis=="X" then y=math.cos(ang)*RADIUS;z=math.sin(ang)*RADIUS elseif cp.ring.axis=="Y" then x=math.cos(ang)*RADIUS;z=math.sin(ang)*RADIUS else x=math.cos(ang)*RADIUS;y=math.sin(ang)*RADIUS end;cp.part.Position=Vector3.new(pos.X+x,pos.Y+y,pos.Z+z);local mix=(math.sin(t*2+cp.idx*0.3)+1)/2;cp.part.Color=Color3.new(col.R*mix+1*(1-mix),col.G*mix+1*(1-mix),col.B*mix+0.3*(1-mix))end end end);showNotif(lbl or "Кристальная клетка включена!",col)end
local function stopCage()cageActive=false;if cageConn then cageConn:Disconnect();cageConn=nil end;for _,p in ipairs(cageParts)do if p and p.Parent then p:Destroy()end end;cageParts={};showNotif("Клетка выключена!",Color3.fromRGB(0,150,200))end

-- Sparks
local sparkActive=false;local sparkConn=nil;local sparkFolder=Instance.new("Folder",workspace);sparkFolder.Name="KittySparks";local sparkParts={}
local function startSparks(col,lbl,rainbow)if sparkConn then sparkConn:Disconnect();sparkConn=nil end;for _,sp in ipairs(sparkParts)do if sp.part and sp.part.Parent then sp.part:Destroy()end end;sparkParts={};sparkActive=true;col=col or globalColor;sparkConn=RS.Heartbeat:Connect(function(dt)local root=getRoot()if not root then return end;local pos=root.Position;local useCol=rainbow and Color3.fromHSV((tick()*0.5)%1,1,1)or col;for i=1,3 do local p=neonPart(0.18,useCol,0.0);p.Position=pos+Vector3.new(0,1,0);p.Parent=sparkFolder;local dir=Vector3.new(math.random(-100,100)/100,math.random(20,100)/100,math.random(-100,100)/100).Unit;table.insert(sparkParts,{part=p,born=tick(),vel=dir*(8+math.random()*14)})end;local now=tick();for i=#sparkParts,1,-1 do local sp=sparkParts[i];if sp.part and sp.part.Parent then local age=now-sp.born;local life=0.75;if age>life then sp.part:Destroy();table.remove(sparkParts,i)else local t=age/life;sp.vel=sp.vel+Vector3.new(0,-18*dt,0);sp.part.Position=sp.part.Position+sp.vel*dt;sp.part.Transparency=t*0.97;local s=0.18*(1-t*0.8);sp.part.Size=Vector3.new(s,s,s)end else table.remove(sparkParts,i)end end end);showNotif(lbl or "Искры включены!",col)end
local function stopSparks()sparkActive=false;if sparkConn then sparkConn:Disconnect();sparkConn=nil end;for _,sp in ipairs(sparkParts)do if sp.part and sp.part.Parent then sp.part:Destroy()end end;sparkParts={};showNotif("Искры выключены!",Color3.fromRGB(150,120,0))end

